{
  "name": "NutriVision AI",
  "description": "An intelligent food analysis tool that uses computer vision to estimate calories, break down ingredients, and provide nutritional insights from food images.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Ingredient {
  name: string;
  quantity: string;
  calories: number;
}

export interface NutritionAnalysis {
  foodName: string;
  portionSize: string;
  assumptions: string;
  ingredients: Ingredient[];
  totalCalories: number;
  simpleExplanation: string;
  disclaimer: string;
  healthyTips?: string[];
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
}

export enum AppState {
  IDLE = 'IDLE',
  ANALYZING = 'ANALYZING',
  RESULTS = 'RESULTS',
  ERROR = 'ERROR'
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { NutritionAnalysis } from "../types";

const apiKey = process.env.API_KEY;

if (!apiKey) {
  console.error("API Key is missing. Please ensure process.env.API_KEY is set.");
}

const ai = new GoogleGenAI({ apiKey: apiKey || 'dummy-key-for-types' });

// Define the schema for the nutrition analysis to ensure consistent JSON output
const nutritionSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    foodName: { type: Type.STRING, description: "Name of the identified food" },
    portionSize: { type: Type.STRING, description: "Estimated portion size (e.g., '1 medium bowl')" },
    assumptions: { type: Type.STRING, description: "Assumptions made about the food (e.g., 'Assumed cooked with olive oil')" },
    ingredients: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          quantity: { type: Type.STRING },
          calories: { type: Type.NUMBER },
        },
        required: ["name", "quantity", "calories"],
      },
    },
    totalCalories: { type: Type.NUMBER, description: "Sum of all ingredient calories" },
    simpleExplanation: { type: Type.STRING, description: "A simple, non-technical explanation of the calorie source" },
    disclaimer: { type: Type.STRING, description: "Standard medical disclaimer" },
    healthyTips: { 
        type: Type.ARRAY, 
        items: { type: Type.STRING },
        description: "Short tips on how to make this healthier or what nutrients it provides" 
    }
  },
  required: ["foodName", "portionSize", "assumptions", "ingredients", "totalCalories", "simpleExplanation", "disclaimer"],
};

export const analyzeImageConfig = {
  model: 'gemini-2.5-flash-image', // Good balance of speed and vision capabilities
  generationConfig: {
    responseMimeType: "application/json",
    responseSchema: nutritionSchema,
    temperature: 0.4, // Keep it factual
  }
};

export const analyzeFoodImage = async (base64Image: string, mimeType: string): Promise<NutritionAnalysis> => {
  try {
    const response = await ai.models.generateContent({
      model: analyzeImageConfig.model,
      contents: {
        parts: [
          {
            inlineData: {
              data: base64Image,
              mimeType: mimeType,
            },
          },
          {
            text: `You are a professional AI Nutrition Analyst. Analyze the food in this image.

            Follow this process:
            1. Identify the food item(s).
            2. Estimate the portion size based on visual cues.
            3. Break down the food into logical ingredients (base, toppings, oils, sauces).
            4. Estimate calories for each ingredient using standard database averages.
            5. Sum the total calories.
            6. Provide a simple explanation suitable for a non-technical user.
            7. Add a medical disclaimer.

            Return the result strictly as a JSON object matching the provided schema.`
          }
        ]
      },
      config: analyzeImageConfig.generationConfig
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as NutritionAnalysis;

  } catch (error) {
    console.error("Error analyzing image:", error);
    throw error;
  }
};

export const sendFollowUpMessage = async (
  history: { role: string; parts: { text: string }[] }[],
  message: string,
  currentContext: NutritionAnalysis
): Promise<string> => {
  try {
    // We use a chat model for the conversation, providing the context of the analysis
    const chat = ai.chats.create({
      model: "gemini-3-flash-preview", // Use a text-optimized model for follow-up chat
      config: {
        systemInstruction: `You are a helpful AI Nutritionist. 
        The user has just had a food image analyzed.

        Context of the food analyzed:
        Food: ${currentContext.foodName}
        Ingredients: ${JSON.stringify(currentContext.ingredients)}
        Total Calories: ${currentContext.totalCalories}

        Answer the user's follow-up questions politely, scientifically, and encouragingly.
        Do not be judgmental. Keep answers concise (under 3 sentences unless asked for detail).`
      },
      history: history // Pass previous chat history
    });

    const result = await chat.sendMessage({ message });
    return result.text || "I couldn't generate a response. Please try again.";
  } catch (error) {
    console.error("Chat error:", error);
    return "Sorry, I'm having trouble connecting right now.";
  }
};

import React, { useCallback, useState } from 'react';
import { Upload, Camera, Image as ImageIcon } from 'lucide-react';

interface ImageUploaderProps {
  onImageSelect: (file: File) => void;
}

const ImageUploader: React.FC<ImageUploaderProps> = ({ onImageSelect }) => {
  const [dragActive, setDragActive] = useState(false);

  const handleDrag = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  }, []);

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      onImageSelect(e.dataTransfer.files[0]);
    }
  }, [onImageSelect]);

  const handleChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    e.preventDefault();
    if (e.target.files && e.target.files[0]) {
      onImageSelect(e.target.files[0]);
    }
  }, [onImageSelect]);

  return (
    <div className="w-full max-w-xl mx-auto">
      <div
        className={`relative group flex flex-col items-center justify-center w-full h-80 border-2 border-dashed rounded-3xl transition-all duration-300 ease-in-out cursor-pointer overflow-hidden
        ${dragActive ? 'border-emerald-500 bg-emerald-50' : 'border-slate-300 bg-white hover:bg-slate-50 hover:border-emerald-400'}`}
        onDragEnter={handleDrag}
        onDragLeave={handleDrag}
        onDragOver={handleDrag}
        onDrop={handleDrop}
      >
        <input
          type="file"
          className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
          accept="image/*"
          onChange={handleChange}
        />

        <div className="flex flex-col items-center justify-center pt-5 pb-6 text-center px-4">
          <div className="mb-4 p-4 bg-emerald-100 rounded-full text-emerald-600 group-hover:scale-110 transition-transform duration-300">
            <Camera size={48} strokeWidth={1.5} />
          </div>
          <p className="mb-2 text-xl font-semibold text-slate-700">
            Analyze your meal
          </p>
          <p className="mb-4 text-sm text-slate-500">
            <span className="font-semibold text-emerald-600">Click to upload</span> or drag and drop
          </p>
          <p className="text-xs text-slate-400 mt-2">
            Supports: JPG, PNG, WEBP
          </p>
        </div>
      </div>
    </div>
  );
};

export default ImageUploader;

import React, { useState, useRef, useEffect } from 'react';
import { Send, User, Sparkles } from 'lucide-react';
import { ChatMessage } from '../types';

interface ChatInterfaceProps {
  chatHistory: ChatMessage[];
  onSendMessage: (message: string) => void;
  isSending: boolean;
}

const ChatInterface: React.FC<ChatInterfaceProps> = ({ chatHistory, onSendMessage, isSending }) => {
  const [input, setInput] = useState('');
  const bottomRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [chatHistory]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isSending) return;
    onSendMessage(input);
    setInput('');
  };

  return (
    <div className="w-full max-w-4xl mx-auto bg-white rounded-3xl shadow-lg border border-slate-100 overflow-hidden mt-8 flex flex-col h-[500px]">
      <div className="p-4 border-b border-slate-100 bg-slate-50/50">
        <h3 className="font-bold text-slate-800 flex items-center gap-2">
          <Sparkles className="w-5 h-5 text-emerald-500" />
          Ask AI Nutritionist
        </h3>
        <p className="text-xs text-slate-500">Ask about healthiness, alternatives, or recipes.</p>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50/30">
        {chatHistory.length === 0 && (
            <div className="text-center text-slate-400 mt-20">
                <p>No questions yet.</p>
                <p className="text-sm">Try asking: "Is this healthy?" or "How can I reduce the calories?"</p>
            </div>
        )}
        {chatHistory.map((msg, index) => (
          <div
            key={index}
            className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
          >
            <div
              className={`max-w-[80%] rounded-2xl p-4 text-sm ${
                msg.role === 'user'
                  ? 'bg-emerald-600 text-white rounded-tr-none shadow-md'
                  : 'bg-white text-slate-700 border border-slate-200 rounded-tl-none shadow-sm'
              }`}
            >
              {msg.text}
            </div>
          </div>
        ))}
        {isSending && (
          <div className="flex justify-start">
            <div className="bg-white p-4 rounded-2xl rounded-tl-none shadow-sm border border-slate-200">
              <div className="flex space-x-2">
                <div className="w-2 h-2 bg-slate-300 rounded-full animate-bounce" style={{ animationDelay: '0ms' }}></div>
                <div className="w-2 h-2 bg-slate-300 rounded-full animate-bounce" style={{ animationDelay: '150ms' }}></div>
                <div className="w-2 h-2 bg-slate-300 rounded-full animate-bounce" style={{ animationDelay: '300ms' }}></div>
              </div>
            </div>
          </div>
        )}
        <div ref={bottomRef} />
      </div>

      <form onSubmit={handleSubmit} className="p-4 bg-white border-t border-slate-100">
        <div className="relative flex items-center">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Ask a follow-up question..."
            className="w-full py-3 pl-4 pr-12 bg-slate-100 text-slate-800 rounded-xl focus:outline-none focus:ring-2 focus:ring-emerald-500 focus:bg-white transition-all"
          />
          <button
            type="submit"
            disabled={!input.trim() || isSending}
            className="absolute right-2 p-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
          >
            <Send className="w-4 h-4" />
          </button>
        </div>
      </form>
    </div>
  );
};

export default ChatInterface;

import React, { useState } from 'react';
import ImageUploader from './components/ImageUploader';
import AnalysisResult from './components/AnalysisResult';
import ChatInterface from './components/ChatInterface';
import { analyzeFoodImage, sendFollowUpMessage } from './services/geminiService';
import { NutritionAnalysis, AppState, ChatMessage } from './types';
import { Loader2, ArrowLeft, Leaf } from 'lucide-react';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.IDLE);
  const [analysisData, setAnalysisData] = useState<NutritionAnalysis | null>(null);
  const [imagePreview, setImagePreview] = useState<string | null>(null);
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
  const [isChatSending, setIsChatSending] = useState(false);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  const handleImageSelect = async (file: File) => {
    try {
      setAppState(AppState.ANALYZING);
      setErrorMsg(null);

      // Create preview
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64String = reader.result as string;
        setImagePreview(base64String);

        // Extract pure base64 for API (remove data:image/xxx;base64,)
        const base64Data = base64String.split(',')[1];

        try {
          const result = await analyzeFoodImage(base64Data, file.type);
          setAnalysisData(result);
          setAppState(AppState.RESULTS);
          // Initialize chat history with empty state
          setChatHistory([]); 
        } catch (err) {
          console.error(err);
          setErrorMsg("Failed to analyze the image. It might not be food, or the AI service is busy. Please try again.");
          setAppState(AppState.ERROR);
        }
      };
      reader.readAsDataURL(file);
    } catch (err) {
      setErrorMsg("Error processing file.");
      setAppState(AppState.ERROR);
    }
  };

  const handleSendMessage = async (text: string) => {
    if (!analysisData) return;

    // Add user message immediately
    const newUserMsg: ChatMessage = { role: 'user', text };
    const updatedHistory = [...chatHistory, newUserMsg];
    setChatHistory(updatedHistory);
    setIsChatSending(true);

    try {
      // Format history for API (map 'model' to 'model', 'user' to 'user')
      const apiHistory = updatedHistory.slice(0, -1).map(msg => ({
        role: msg.role === 'model' ? 'model' : 'user',
        parts: [{ text: msg.text }]
      }));

      const responseText = await sendFollowUpMessage(apiHistory, text, analysisData);

      setChatHistory(prev => [...prev, { role: 'model', text: responseText }]);
    } catch (err) {
      console.error(err);
      setChatHistory(prev => [...prev, { role: 'model', text: "Sorry, I couldn't process that request." }]);
    } finally {
      setIsChatSending(false);
    }
  };

  const resetApp = () => {
    setAppState(AppState.IDLE);
    setAnalysisData(null);
    setImagePreview(null);
    setChatHistory([]);
    setErrorMsg(null);
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-800 font-sans selection:bg-emerald-100 selection:text-emerald-900 pb-20">

      {/* Navbar */}
      <nav className="bg-white border-b border-slate-200 sticky top-0 z-50">
        <div className="max-w-6xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2 cursor-pointer" onClick={resetApp}>
            <div className="bg-emerald-500 p-1.5 rounded-lg text-white">
              <Leaf size={20} />
            </div>
            <h1 className="text-xl font-bold tracking-tight text-slate-800">Nutri<span className="text-emerald-600">Vision</span> AI</h1>
          </div>
          {appState === AppState.RESULTS && (
             <button 
                onClick={resetApp}
                className="text-sm font-medium text-slate-500 hover:text-emerald-600 flex items-center gap-1 transition-colors"
             >
               <ArrowLeft size={16} />
               New Analysis
             </button>
          )}
        </div>
      </nav>

      <main className="max-w-6xl mx-auto px-4 pt-8">

        {appState === AppState.IDLE && (
          <div className="flex flex-col items-center justify-center min-h-[60vh] space-y-8 animate-fade-in-up">
            <div className="text-center max-w-2xl mx-auto space-y-4">
              <h2 className="text-4xl md:text-5xl font-extrabold text-slate-900 tracking-tight leading-tight">
                Instantly track calories <br className="hidden md:block"/>
                <span className="text-transparent bg-clip-text bg-gradient-to-r from-emerald-500 to-teal-400">with just a photo</span>
              </h2>
              <p className="text-lg text-slate-500">
                Advanced AI analysis breaks down ingredients, estimates portions, and provides nutritional insights in seconds.
              </p>
            </div>
            <ImageUploader onImageSelect={handleImageSelect} />

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mt-12 w-full max-w-4xl opacity-80">
              {[
                { title: "Smart Recognition", desc: "Identifies complex dishes & ingredients" },
                { title: "Calorie Breakdown", desc: "Detailed estimated calories per ingredient" },
                { title: "Nutrition Advice", desc: "Get AI-powered health tips & answers" }
              ].map((feature, i) => (
                <div key={i} className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm text-center">
                  <h3 className="font-bold text-slate-800 mb-2">{feature.title}</h3>
                  <p className="text-sm text-slate-500">{feature.desc}</p>
                </div>
              ))}
            </div>
          </div>
        )}

        {appState === AppState.ANALYZING && (
          <div className="flex flex-col items-center justify-center min-h-[60vh] text-center">
            <div className="relative mb-8">
              <div className="absolute inset-0 bg-emerald-200 rounded-full animate-ping opacity-25"></div>
              <div className="relative bg-white p-4 rounded-full shadow-lg border border-emerald-100">
                <Loader2 className="w-12 h-12 text-emerald-500 animate-spin" />
              </div>
            </div>
            <h3 className="text-2xl font-bold text-slate-800 mb-2">Analyzing your food...</h3>
            <p className="text-slate-500 max-w-md">
              Identifying ingredients, estimating portions, and calculating nutritional values. This usually takes 5-10 seconds.
            </p>
            {imagePreview && (
              <div className="mt-8 w-48 h-48 rounded-2xl overflow-hidden shadow-lg border-4 border-white opacity-50 grayscale">
                <img src={imagePreview} className="w-full h-full object-cover" alt="Analyzing" />
              </div>
            )}
          </div>
        )}

        {appState === AppState.ERROR && (
           <div className="flex flex-col items-center justify-center min-h-[50vh] text-center max-w-md mx-auto">
             <div className="bg-red-50 p-4 rounded-full mb-6">
               <ArrowLeft className="w-10 h-10 text-red-500" />
             </div>
             <h3 className="text-2xl font-bold text-slate-800 mb-2">Oops! Something went wrong.</h3>
             <p className="text-slate-500 mb-8">{errorMsg || "We couldn't analyze that image. Please ensure it's a clear photo of food."}</p>
             <button 
               onClick={resetApp}
               className="bg-slate-900 text-white px-8 py-3 rounded-xl font-medium hover:bg-slate-800 transition-colors shadow-lg shadow-slate-200"
             >
               Try Again
             </button>
           </div>
        )}

        {appState === AppState.RESULTS && analysisData && (
          <div className="space-y-12">
            <AnalysisResult data={analysisData} imagePreview={imagePreview} />
            <ChatInterface 
              chatHistory={chatHistory} 
              onSendMessage={handleSendMessage} 
              isSending={isChatSending} 
            />
          </div>
        )}

      </main>
    </div>
  );
};

export default App;

